struct fuse_in_header {
  uint32_t len;
  uint32_t opcode;
  uint64_t unique;
  uint64_t nodeid;
  uint32_t uid;
  uint32_t gid;
  uint32_t pid;
  uint32_t padding;
};
struct fuse_out_header {
  uint32_t len;
  uint32_t error;
  uint64_t unique;
};
struct syz_fuse_req_out {
  struct fuse_out_header* init;
  struct fuse_out_header* lseek;
  struct fuse_out_header* bmap;
  struct fuse_out_header* poll;
  struct fuse_out_header* getxattr;
  struct fuse_out_header* lk;
  struct fuse_out_header* statfs;
  struct fuse_out_header* write;
  struct fuse_out_header* read;
  struct fuse_out_header* open;
  struct fuse_out_header* attr;
  struct fuse_out_header* entry;
  struct fuse_out_header* dirent;
  struct fuse_out_header* direntplus;
  struct fuse_out_header* create_open;
  struct fuse_out_header* ioctl;
  struct fuse_out_header* statx;
};
static int fuse_send_response(int fd, const struct fuse_in_header* in_hdr,
                              struct fuse_out_header* out_hdr)
{
  if (!out_hdr) {
    return -1;
  }
  out_hdr->unique = in_hdr->unique;
  if (write(fd, out_hdr, out_hdr->len) == -1) {
    return -1;
  }
  return 0;
}
static volatile long syz_fuse_handle_req(volatile long a0, volatile long a1,
                                         volatile long a2, volatile long a3)
{
  struct syz_fuse_req_out* req_out = (struct syz_fuse_req_out*)a3;
  struct fuse_out_header* out_hdr = NULL;
  char* buf = (char*)a1;
  int buf_len = (int)a2;
  int fd = (int)a0;
  if (!req_out) {
    return -1;
  }
  if (buf_len < FUSE_MIN_READ_BUFFER) {
    return -1;
  }
  int ret = read(fd, buf, buf_len);
  if (ret == -1) {
    return -1;
  }
  if ((size_t)ret < sizeof(struct fuse_in_header)) {
    return -1;
  }
  const struct fuse_in_header* in_hdr = (const struct fuse_in_header*)buf;
  if (in_hdr->len > (uint32_t)ret) {
    return -1;
  }
  switch (in_hdr->opcode) {
  case FUSE_GETATTR:
  case FUSE_SETATTR:
    out_hdr = req_out->attr;
    break;
  case FUSE_LOOKUP:
  case FUSE_SYMLINK:
  case FUSE_LINK:
  case FUSE_MKNOD:
  case FUSE_MKDIR:
    out_hdr = req_out->entry;
    break;
  case FUSE_OPEN:
  case FUSE_OPENDIR:
    out_hdr = req_out->open;
    break;
  case FUSE_STATFS:
    out_hdr = req_out->statfs;
    break;
  case FUSE_RMDIR:
  case FUSE_RENAME:
  case FUSE_RENAME2:
  case FUSE_FALLOCATE:
  case FUSE_SETXATTR:
  case FUSE_REMOVEXATTR:
  case FUSE_FSYNCDIR:
  case FUSE_FSYNC:
  case FUSE_SETLKW:
  case FUSE_SETLK:
  case FUSE_ACCESS:
  case FUSE_FLUSH:
  case FUSE_RELEASE:
  case FUSE_RELEASEDIR:
  case FUSE_UNLINK:
  case FUSE_DESTROY:
    out_hdr = req_out->init;
    if (!out_hdr) {
      return -1;
    }
    out_hdr->len = sizeof(struct fuse_out_header);
    break;
  case FUSE_READ:
    out_hdr = req_out->read;
    break;
  case FUSE_READDIR:
    out_hdr = req_out->dirent;
    break;
  case FUSE_READDIRPLUS:
    out_hdr = req_out->direntplus;
    break;
  case FUSE_INIT:
    out_hdr = req_out->init;
    break;
  case FUSE_LSEEK:
    out_hdr = req_out->lseek;
    break;
  case FUSE_GETLK:
    out_hdr = req_out->lk;
    break;
  case FUSE_BMAP:
    out_hdr = req_out->bmap;
    break;
  case FUSE_POLL:
    out_hdr = req_out->poll;
    break;
  case FUSE_GETXATTR:
  case FUSE_LISTXATTR:
    out_hdr = req_out->getxattr;
    break;
  case FUSE_WRITE:
  case FUSE_COPY_FILE_RANGE:
    out_hdr = req_out->write;
    break;
  case FUSE_FORGET:
  case FUSE_BATCH_FORGET:
    return 0;
  case FUSE_CREATE:
    out_hdr = req_out->create_open;
    break;
  case FUSE_IOCTL:
    out_hdr = req_out->ioctl;
    break;
  case FUSE_STATX:
    out_hdr = req_out->statx;
    break;
  default:
    return -1;
  }
  return fuse_send_response(fd, in_hdr, out_hdr);
}

struct thread_t {
  int created, call;
  event_t ready, done;
};

static struct thread_t threads[16];
static void execute_call(int call);
static int running;

static void* thr(void* arg)
{
  struct thread_t* th = (struct thread_t*)arg;
  for (;;) {
    event_wait(&th->ready);
    event_reset(&th->ready);
    execute_call(th->call);
    __atomic_fetch_sub(&running, 1, __ATOMIC_RELAXED);
    event_set(&th->done);
  }
  return 0;
}

static void execute_one(void)
{
  if (write(1, "executing program\n", sizeof("executing program\n") - 1)) {
  }
  int i, call, thread;
  for (call = 0; call < 7; call++) {
    for (thread = 0; thread < (int)(sizeof(threads) / sizeof(threads[0]));
         thread++) {
      struct thread_t* th = &threads[thread];
      if (!th->created) {
        th->created = 1;
        event_init(&th->ready);
        event_init(&th->done);
        event_set(&th->done);
        thread_start(thr, th);
      }
      if (!event_isset(&th->done))
        continue;
      event_reset(&th->done);
      th->call = call;
      __atomic_fetch_add(&running, 1, __ATOMIC_RELAXED);
      event_set(&th->ready);
      if (call == 5)
        break;
      event_timedwait(&th->done, 50 + (call == 1 ? 4000 : 0));
      break;
    }
  }
  for (i = 0; i < 100 && __atomic_load_n(&running, __ATOMIC_RELAXED); i++)
    sleep_ms(1);
}

static void execute_one(void);

#define WAIT_FLAGS __WALL

static void loop(void)
{
  int iter = 0;
  for (;; iter++) {
    char cwdbuf[32];
    sprintf(cwdbuf, "./%d", iter);
    if (mkdir(cwdbuf, 0777))
      exit(1);
    reset_loop();
    int pid = fork();
    if (pid < 0)
      exit(1);
    if (pid == 0) {
      if (chdir(cwdbuf))
        exit(1);
      setup_test();
      execute_one();
      exit(0);
    }
    int status = 0;
    uint64_t start = current_time_ms();
    for (;;) {
      sleep_ms(10);
      if (waitpid(-1, &status, WNOHANG | WAIT_FLAGS) == pid)
        break;
      if (current_time_ms() - start < 5000)
        continue;
      kill_and_wait(pid, &status);
      break;
    }
    remove_dir(cwdbuf);
  }
}

